func solve(edges [][]int64, online []bool, k int64) int64 {
    n := len(online)
    adj := make([][]struct{ v, cost int64 }, n)
    in_degree := make([]int, n)
    for _, edge := range edges {
        u := edge[0]
        v := edge[1]
        cost := edge[2]
        adj[u] = append(adj[u], struct{ v, cost int64 }{v, cost})
        in_degree[v]++
    }

    // Topological sort
    q := []int{}
    for i := 0; i < n; i++ {
        if in_degree[i] == 0 {
            q = append(q, i)
        }
    }

    topo := []int{}
    for len(q) > 0 {
        u := q[0]
        q = q[1:]
        topo = append(topo, u)
        for _, neighbor := range adj[u] {
            in_degree[neighbor.v]--
            if in_degree[neighbor.v] == 0 {
                q = append(q, neighbor.v)
            }
        }
    }

    // Initialize best_min and best_sum
    best_min := make([]int64, n)
    best_sum := make([]int64, n)
    for i := 0; i < n; i++ {
        best_min[i] = -1000000000000000000
    }
    best_min[0] = 1000000000000000000
    for i := 0; i < n; i++ {
        best_sum[i] = 0
    }

    // Process nodes in topological order
    for _, u := range topo {
        if !online[u] {
            continue
        }
        for _, neighbor := range adj[u] {
            v := neighbor.v
            cost := neighbor.cost
            if !online[v] {
                continue
            }
            if best_min[u] == -1000000000000000000 {
                continue
            }
            new_min := best_min[u]
            if cost < new_min {
                new_min = cost
            }
            new_sum := best_sum[u] + cost
            if new_sum > k {
                continue
            }
            if new_min > best_min[v] {
                best_min[v] = new_min
                best_sum[v] = new_sum
            } else if new_min == best_min[v] {
                if new_sum < best_sum[v] {
                    best_sum[v] = new_sum
                }
            }
        }
    }

    if best_min[n-1] == -1000000000000000000 {
        return -1
    }
    return best_min[n-1]
}
