import (
	"math"
)

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}
	adj := make([][]struct{ v, cost int64 }, n)
	inDegree := make([]int, n)
	for _, edge := range edges {
		u := edge[0]
		v := edge[1]
		cost := edge[2]
		adj[u] = append(adj[u], struct{ v, cost int64 }{v, cost})
		inDegree[v]++
	}
	topo := []int{}
	q := []int{}
	for i := 0; i < n; i++ {
		if inDegree[i] == 0 {
			q = append(q, i)
		}
	}
	for len(q) > 0 {
		u := q[0]
		q = q[1:]
		topo = append(topo, u)
		for _, neighbor := range adj[u] {
			inDegree[neighbor.v]--
			if inDegree[neighbor.v] == 0 {
				q = append(q, neighbor.v)
			}
		}
	}
	best_min := make([]int64, n)
	best_sum := make([]int64, n)
	for i := 0; i < n; i++ {
		best_min[i] = math.MinInt64
	}
	best_min[0] = math.MaxInt64
	best_sum[0] = 0
	for _, u := range topo {
		if !online[u] {
			continue
		}
		for _, neighbor := range adj[u] {
			v := neighbor.v
			cost := neighbor.cost
			if !online[v] {
				continue
			}
			current_min := best_min[u]
			if current_min == math.MinInt64 {
				continue
			}
			new_min := min(current_min, cost)
			new_sum := best_sum[u] + cost
			if new_sum > k {
				continue
			}
			if new_min > best_min[v] {
				best_min[v] = new_min
				best_sum[v] = new_sum
			} else if new_min == best_min[v] && new_sum < best_sum[v] {
				best_sum[v] = new_sum
			}
		}
	}
	if best_min[n-1] == math.MinInt64 {
		return -1
	}
	return best_min[n-1]
}
