from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        adj[u].append((v, cost))
        in_degree[v] += 1

    # Topological sort
    topo = []
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    while q:
        u = q.popleft()
        topo.append(u)
        for v, _ in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Initialize best_min and best_sum
    best_min = [-float('inf')] * n
    best_sum = [0] * n
    best_min[0] = float('inf')

    # Process nodes in topological order
